"use client";

import * as React from "react";
import type {
  ComposerCtx,
  ComposerDraft,
  ComposerStepCtx,
  ComposerStepValue,
  ContentCardItem,
  ContentComposer01Handle,
  ContentComposer01Props,
  ExportMetadata,
  GateResult,
  SlotHandle,
  SlotKind,
  SlotValueFor,
} from "./types";
import { makeEmptyDraft } from "./lib/reducer";
import { DEFAULT_SUBSTRATES } from "./lib/substrates";
import { evaluateStep } from "./lib/gates";
import { resolveUploader } from "./lib/upload";
import { resolvePublishCtaArms } from "./lib/publish-cta";
import { getAdapter } from "./adapters/adapter-registry";
import { useComposerState } from "./hooks/use-composer-state";
import { useSlotHandles } from "./hooks/use-slot-handles";
import { useAutosave } from "./hooks/use-autosave";
import { ComposerContext, ComposerStepContext } from "./hooks/use-composer-context";
import { ComposerShell } from "./parts/composer-shell";
import { ComposerDialog } from "./parts/composer-dialog";
import { SlotMount } from "./parts/slot-mount";
import { CarouselLiveCacheContext } from "./parts/media-carousel-substrate";
import type { MediaCarouselItem } from "@/registry/components/media/media-carousel-editor-01/media-carousel-editor-01";
import { PublishBar } from "./parts/publish-bar";

function errorMessage(e: unknown): string {
  return e instanceof Error ? e.message : String(e);
}

/**
 * content-composer-01 — the multi-step content-authoring SHELL.
 *
 * One JSON `ComposerConfig` per content type drives the steps; each step's slot
 * is rendered by a substrate (json-form / article-body-01 / media-editor-01).
 * The shell owns step navigation + the blocking gates, autosave (draft-level
 * dirty), the draft → publish → schedule FSM, lazy upload-on-publish, and the
 * per-content-type adapter to the backend `ContentCardItem`.
 */
export const ContentComposer01 = React.forwardRef<
  ContentComposer01Handle,
  ContentComposer01Props
>(function ContentComposer01(props, ref) {
  const { config } = props;

  // ── Seed (T1): controlled value wins; else defaultValue; else inverse-adapter
  //    from initialItem; the body always re-seeds via the separate initialBody leg.
  const [initialDraft] = React.useState<ComposerDraft>(() => {
    const base = props.defaultValue ?? makeEmptyDraft(config.id);
    let seeded = base;
    if (!props.defaultValue && props.initialItem) {
      const adapter = getAdapter(config.adapterId);
      if (adapter) {
        const { draft: seed } = adapter.fromContentItem(props.initialItem);
        seeded = {
          ...base,
          ...seed,
          steps: { ...base.steps, ...(seed.steps ?? {}) },
        };
      }
    }
    if (props.initialBody) {
      const bodyStep = config.steps.find((s) => s.slot === "bodySlot");
      if (bodyStep) {
        seeded = {
          ...seeded,
          steps: {
            ...seeded.steps,
            [bodyStep.id]: { slot: "bodySlot", value: props.initialBody },
          },
        };
      }
    }
    return seeded;
  });

  const { draft, dispatch, phase, dispatchPhase } = useComposerState({
    contentType: config.id,
    value: props.value,
    defaultValue: initialDraft,
    onChange: props.onDraftChange,
  });

  const substrateMap = React.useMemo(
    () => ({ ...DEFAULT_SUBSTRATES, ...props.substrates }),
    [props.substrates],
  );

  const { registerHandle, getHandle } = useSlotHandles();
  const { isDirty, markSaved } = useAutosave({
    draft,
    phase,
    autosave: props.autosave,
    onAutosave: props.onAutosave,
    debounceMs: config.autosave?.debounceMs,
    dispatchPhase,
  });

  const blobMap = React.useRef(new Map<string, Blob>());
  // Live carousel items (with blobs) per step — keeps mediaCarouselSlot media
  // across step navigation (the carousel runs with revokeOnUnmount={false}, so
  // its object URLs outlive a step unmount; we revoke them on composer unmount).
  const carouselCache = React.useRef(new Map<string, MediaCarouselItem[]>());
  React.useEffect(() => {
    const cache = carouselCache.current;
    return () => {
      cache.forEach((items) =>
        items.forEach((it) => {
          if (it.url.startsWith("blob:")) URL.revokeObjectURL(it.url);
        }),
      );
      cache.clear();
    };
  }, []);
  // Enter the editing phase on mount (FSM `idle → editing`, T0). Without this the
  // phase stays "idle" and every gate-guarded action silently no-ops: `goToStep`
  // refuses (`phase !== "editing"`), and save/publish never leave idle. `start`
  // is idempotent (only acts on "idle"), so the dev double-invoke is harmless.
  React.useEffect(() => {
    dispatchPhase({ type: "start" });
  }, [dispatchPhase]);

  const rootRef = React.useRef<HTMLDivElement>(null);
  const [announcement, setAnnouncement] = React.useState("");
  // Visible (not just sr-only) lifecycle error — e.g. a save/publish that hits an
  // unregistered adapter or a rejected callback. Cleared on the next nav/save.
  const [lifecycleError, setLifecycleError] = React.useState<string | null>(null);
  const [stepErrors, setStepErrors] = React.useState<Record<string, string[]>>({});
  const [scheduleValue, setScheduleValue] = React.useState("");

  const presentation = props.presentation ?? config.presentation ?? "auto";
  const resolvedMode: "inline" | "dialog" =
    presentation === "dialog" ? "dialog" : "inline";

  // ── Focus + announce on a blocked gate ──────────────────────────────────
  const jumpToFirstInvalid = React.useCallback(
    (stepIndex: number, res: GateResult) => {
      const step = config.steps[stepIndex];
      if (!step) return;
      dispatch({ type: "set-cursor", cursor: stepIndex });
      const msg =
        res.errors?.[step.id]?.[0] ??
        `Please complete “${step.title}” before continuing.`;
      setStepErrors({ [step.id]: [msg] });
      setAnnouncement(msg);
      requestAnimationFrame(() => {
        const el = rootRef.current?.querySelector<HTMLElement>(
          '[data-composer-step-body] :is(input,textarea,select,button,[tabindex],[contenteditable="true"])',
        );
        el?.focus();
      });
    },
    [config, dispatch],
  );

  // ── Pull-only media capture at step-leave (blob stored, uploaded at publish) ─
  const captureMediaBlob = React.useCallback(
    async (stepId: string) => {
      const handle = getHandle(stepId);
      if (!handle?.export) return;
      const sv = draft.steps[stepId];
      const mv = sv?.slot === "mediaSlot" ? sv.value : undefined;
      if (mv?.exportedUrl) return; // re-edit of an existing hero — no re-export
      if (!handle.getIsDirty() && mv?.pendingBlobRef) return; // unchanged capture
      try {
        const { blob, metadata } = await handle.export();
        blobMap.current.set(stepId, blob);
        dispatch({
          type: "set-step-value",
          stepId,
          value: {
            slot: "mediaSlot",
            value: { ...mv, pendingBlobRef: stepId, exportMetadata: metadata },
          },
        });
      } catch {
        // export failed — leave the value as-is; publish surfaces the error.
      }
    },
    [draft, getHandle, dispatch],
  );

  // ── Navigation: backward free, forward gated ────────────────────────────
  const goToStep = React.useCallback(
    async (target: number): Promise<GateResult> => {
      if (phase !== "editing") return { ok: false };
      setLifecycleError(null);
      const max = config.steps.length - 1;
      const clamped = Math.max(0, Math.min(target, max));
      const from = draft.cursor;
      if (clamped <= from) {
        dispatch({ type: "set-cursor", cursor: clamped });
        return { ok: true };
      }
      for (let i = from; i < clamped; i++) {
        const activeHandle =
          i === from ? getHandle(config.steps[i].id) : undefined;
        const res = await evaluateStep(config, i, draft, { activeHandle });
        if (!res.ok) {
          jumpToFirstInvalid(i, res);
          return res;
        }
        if (i === from && config.steps[i].slot === "mediaSlot") {
          await captureMediaBlob(config.steps[i].id);
        }
      }
      setStepErrors({});
      dispatch({ type: "set-cursor", cursor: clamped });
      requestAnimationFrame(() => {
        rootRef.current
          ?.querySelector<HTMLElement>(
            '[data-composer-step-body] :is(input,textarea,select,button,[tabindex],[contenteditable="true"])',
          )
          ?.focus();
      });
      return { ok: true };
    },
    [phase, draft, config, getHandle, dispatch, jumpToFirstInvalid, captureMediaBlob],
  );

  // ── Publish/Schedule re-run ALL gates ───────────────────────────────────
  const runAllGates = React.useCallback(async (): Promise<GateResult> => {
    for (let i = 0; i < config.steps.length; i++) {
      const activeHandle =
        i === draft.cursor ? getHandle(config.steps[i].id) : undefined;
      const res = await evaluateStep(config, i, draft, { activeHandle });
      if (!res.ok) {
        jumpToFirstInvalid(i, res);
        return res;
      }
    }
    return { ok: true };
  }, [config, draft, getHandle, jumpToFirstInvalid]);

  // ── Upload-on-publish (QP-10) + adapter assembly ────────────────────────
  const uploadHero = React.useCallback(
    async (snapshot: ComposerDraft): Promise<ComposerDraft> => {
      const uploader = resolveUploader(props.uploader, props.uploadUrl);
      let next = snapshot;
      for (const step of config.steps) {
        if (step.slot !== "mediaSlot") continue;
        const sv = next.steps[step.id];
        const mv = sv?.slot === "mediaSlot" ? sv.value : undefined;
        if (!mv || mv.exportedUrl) continue; // none, or already uploaded
        let exported: { blob: Blob; metadata: ExportMetadata } | undefined;
        if (mv.pendingBlobRef && blobMap.current.has(mv.pendingBlobRef) && mv.exportMetadata) {
          exported = {
            blob: blobMap.current.get(mv.pendingBlobRef)!,
            metadata: mv.exportMetadata,
          };
        } else {
          const handle = getHandle(step.id);
          if (handle?.export) exported = await handle.export();
        }
        if (!exported) continue; // no hero → toContentItem throws (image required)
        if (!uploader) {
          throw new Error(
            "content-composer-01: no `uploader`/`uploadUrl` provided to upload the hero.",
          );
        }
        const { url } = await uploader(exported.blob, exported.metadata);
        next = {
          ...next,
          steps: {
            ...next.steps,
            [step.id]: {
              slot: "mediaSlot",
              value: { ...mv, exportedUrl: url, exportMetadata: exported.metadata },
            },
          },
        };
      }
      return next;
    },
    [props.uploader, props.uploadUrl, config, getHandle],
  );

  const assembleItem = React.useCallback(
    async (
      snapshot: ComposerDraft,
    ): Promise<{ item: ContentCardItem; draft: ComposerDraft }> => {
      const adapter = getAdapter(config.adapterId);
      if (!adapter) {
        throw new Error(
          `content-composer-01: no adapter registered for "${config.adapterId}".`,
        );
      }
      const uploaded = await uploadHero(snapshot);
      const item = adapter.toContentItem(uploaded, { now: new Date() });
      const finalDraft = uploaded.contentId
        ? uploaded
        : { ...uploaded, contentId: item.id };
      dispatch({ type: "replace", draft: finalDraft });
      return { item, draft: finalDraft };
    },
    [config, uploadHero, dispatch],
  );

  // ── Lifecycle exits (FSM T7–T17) ────────────────────────────────────────
  const saveDraft = React.useCallback(async () => {
    const cb = props.onSaveDraft;
    if (!cb) return;
    const snapshot: ComposerDraft = { ...draft, status: "draft" };
    setLifecycleError(null);
    dispatchPhase({ type: "validate-begin" });
    dispatchPhase({ type: "intent-accepted", intent: { mode: "draft" } });
    try {
      const { item, draft: saved } = await assembleItem(snapshot);
      await cb(item);
      markSaved(saved);
      setAnnouncement("Draft saved.");
    } catch (e) {
      setAnnouncement(errorMessage(e));
      setLifecycleError(errorMessage(e));
    } finally {
      dispatchPhase({ type: "draft-ack" });
    }
  }, [props.onSaveDraft, draft, assembleItem, dispatchPhase, markSaved]);

  const publish = React.useCallback(async () => {
    const cb = props.onPublish;
    if (!cb) return;
    setLifecycleError(null);
    dispatchPhase({ type: "validate-begin" });
    const gate = await runAllGates();
    if (!gate.ok) {
      dispatchPhase({ type: "gate-fail" });
      return;
    }
    dispatchPhase({ type: "intent-accepted", intent: { mode: "publish" } });
    try {
      const snapshot: ComposerDraft = { ...draft, status: "published" };
      const { item, draft: saved } = await assembleItem(snapshot);
      await cb(item);
      markSaved(saved);
      setAnnouncement("Published.");
      dispatchPhase({ type: "publish-resolved" });
    } catch (e) {
      setAnnouncement(errorMessage(e));
      setLifecycleError(errorMessage(e));
      dispatchPhase({ type: "publish-rejected" });
    }
  }, [props.onPublish, draft, runAllGates, assembleItem, dispatchPhase, markSaved]);

  const schedule = React.useCallback(
    async (at: Date) => {
      const cb = props.onSchedule;
      if (!cb) return;
      if (!(at instanceof Date) || Number.isNaN(at.getTime()) || at.getTime() <= Date.now()) {
        setAnnouncement("Pick a future time to schedule.");
        return;
      }
      setLifecycleError(null);
      dispatchPhase({ type: "validate-begin" });
      const gate = await runAllGates();
      if (!gate.ok) {
        dispatchPhase({ type: "gate-fail" });
        return;
      }
      dispatchPhase({ type: "intent-accepted", intent: { mode: "schedule", publishAt: at } });
      try {
        const snapshot: ComposerDraft = {
          ...draft,
          status: "scheduled",
          scheduledFor: at.toISOString(),
        };
        const { item, draft: saved } = await assembleItem(snapshot);
        await cb(item, at);
        markSaved(saved);
        setAnnouncement("Scheduled.");
        dispatchPhase({ type: "schedule-resolved" });
      } catch (e) {
        setAnnouncement(errorMessage(e));
        setLifecycleError(errorMessage(e));
        dispatchPhase({ type: "publish-rejected" });
      }
    },
    [props.onSchedule, draft, runAllGates, assembleItem, dispatchPhase, markSaved],
  );

  // ── Imperative handle ───────────────────────────────────────────────────
  React.useImperativeHandle(
    ref,
    (): ContentComposer01Handle => ({
      saveDraft,
      publish,
      schedule,
      goToStep,
      getIsDirty: () => isDirty,
      getDraft: () => draft,
      loadDraft: (d) => dispatch({ type: "replace", draft: d }),
    }),
    [saveDraft, publish, schedule, goToStep, isDirty, draft, dispatch],
  );

  // ── Context + active step ───────────────────────────────────────────────
  const ctx = React.useMemo<ComposerCtx>(
    () => ({
      contentType: config.id,
      phase,
      cursor: draft.cursor,
      steps: config.steps,
      isDirty,
      stepErrors,
      publishModes: config.publishModes,
      goToStep,
      saveDraft,
      publish,
      schedule,
    }),
    [config, phase, draft.cursor, isDirty, stepErrors, goToStep, saveDraft, publish, schedule],
  );

  const activeStep = config.steps[draft.cursor];
  const activeStepValue = activeStep ? draft.steps[activeStep.id]?.value : undefined;

  const stepCtx = React.useMemo<ComposerStepCtx | null>(
    () =>
      activeStep
        ? {
            stepId: activeStep.id,
            contentType: config.id,
            mode: resolvedMode,
            isDirty,
            stepErrors: stepErrors[activeStep.id] ?? [],
          }
        : null,
    [activeStep, config.id, resolvedMode, isDirty, stepErrors],
  );

  const handleSlotChange = React.useCallback(
    (next: SlotValueFor<SlotKind>) => {
      if (!activeStep) return;
      dispatch({
        type: "set-step-value",
        stepId: activeStep.id,
        value: { slot: activeStep.slot, value: next } as ComposerStepValue,
      });
    },
    [activeStep, dispatch],
  );

  // ── Publish bar ─────────────────────────────────────────────────────────
  const scheduleReady = (() => {
    if (!scheduleValue) return false;
    const t = new Date(scheduleValue).getTime();
    return !Number.isNaN(t) && t > Date.now();
  })();
  const arms = resolvePublishCtaArms({
    publishModes: config.publishModes,
    phase,
    hasOnSaveDraft: !!props.onSaveDraft,
    hasOnPublish: !!props.onPublish,
    hasOnSchedule: !!props.onSchedule,
    scheduleReady,
  });

  // Publish / Schedule are terminal actions → only on the final step. Save draft
  // stays on every step (save progress anytime). The shell renders a Next button
  // on non-final steps; the footer sits beside it.
  const isLastStep = draft.cursor >= config.steps.length - 1;
  const placedArms = isLastStep
    ? arms
    : arms.filter((a) => a.mode === "draft");

  const footer = props.renderPublishCTA
    ? props.renderPublishCTA(ctx)
    : placedArms.length > 0
      ? (
          <PublishBar
            arms={placedArms}
            onSaveDraft={() => void saveDraft()}
            onPublish={() => void publish()}
            onSchedule={() => void schedule(new Date(scheduleValue))}
            scheduleValue={scheduleValue}
            onScheduleValueChange={setScheduleValue}
          />
        )
      : null;

  const slotNode =
    activeStep && stepCtx ? (
      <ComposerStepContext.Provider value={stepCtx}>
        <SlotMount
          substrates={substrateMap}
          step={activeStep}
          value={activeStepValue}
          onChange={handleSlotChange}
          ctx={stepCtx}
          // Dispatch-boundary erasure: the per-step registry stores
          // SlotHandle<unknown> (SlotHandle is invariant in TValue via
          // loadValue), so the typed handleRef is cast here — runtime-correct,
          // the substrate populates the concrete handle.
          handleRef={
            registerHandle(activeStep.id) as React.Ref<
              SlotHandle<SlotValueFor<SlotKind>>
            >
          }
        />
      </ComposerStepContext.Provider>
    ) : null;

  const dialogDescription = `${config.steps.length}-step ${config.title} composer. Use the step navigation, then save, publish, or schedule.`;

  return (
    <CarouselLiveCacheContext.Provider value={carouselCache}>
    <ComposerContext.Provider value={ctx}>
      {resolvedMode === "dialog" ? (
        <ComposerDialog
          open={props.isOpen ?? false}
          onOpenChange={(o) => {
            if (!o) props.onClose?.();
          }}
          title={config.title}
          description={dialogDescription}
        >
          <div ref={rootRef}>
            <ComposerShell
              ctx={ctx}
              mode="dialog"
              footer={footer}
              announcement={announcement}
              error={lifecycleError}
              onDismissError={() => setLifecycleError(null)}
            >
              {slotNode}
            </ComposerShell>
          </div>
        </ComposerDialog>
      ) : (
        <div
          ref={rootRef}
          data-slot="content-composer-01"
          data-content-type={config.id}
        >
          <ComposerShell
            ctx={ctx}
            mode="inline"
            footer={footer}
            announcement={announcement}
            error={lifecycleError}
            onDismissError={() => setLifecycleError(null)}
            renderStepChrome={props.renderStepChrome}
          >
            {slotNode}
          </ComposerShell>
        </div>
      )}
    </ComposerContext.Provider>
    </CarouselLiveCacheContext.Provider>
  );
});

export { ContentComposer01 } from "./content-composer-01";

// Headless state (description §10) — for consumers building a custom shell.
export {
  useComposerState,
  type UseComposerStateReturn,
} from "./hooks/use-composer-state";

// Per-mount + per-step context hooks (throw outside their subtree). Exposed so
// consumers' custom field/slot renderers can read the live composer state.
export {
  useComposerContext,
  useComposerStep,
} from "./hooks/use-composer-context";

// Config hydration layer (QP-6) — for consumers deserializing JSON configs and
// re-attaching function escape-hatches before building a ComposerConfig.
export {
  hydrateSchema,
  stripHydration,
  type ComposerConfigHydration,
  type FieldHydration,
  type SchemaHydration,
  type ConditionFn,
} from "./lib/hydration";

// Composer-owned custom json-form field renderers (the two json-form gaps).
// Exported for `fieldRegistry` reuse in consumer schemas.
export { tagsFieldRenderer } from "./parts/field-tags";
export {
  authorPickerFieldRenderer,
  type AuthorEntity,
  type AuthorSourceConfig,
} from "./parts/field-author-picker";

// Default substrate registry + lookup — spreadable + overridable via the
// `substrates` prop. The three records map each closed SlotKind to its mount.
export {
  DEFAULT_SUBSTRATES,
  findSubstrate,
  jsonFormSubstrate,
  articleBodySubstrate,
  mediaEditorSubstrate,
  mediaCarouselSubstrate,
} from "./lib/substrates";
export { CarouselLiveCacheContext } from "./parts/media-carousel-substrate";

// Content-type configs + the runtime adapter registry. The news config is a
// factory (inject `authorSource`); `newsComposerConfig` is the default instance.
export {
  createNewsComposerConfig,
  newsComposerConfig,
  newsContentItemAdapter,
  type NewsComposerConfigOptions,
} from "./configs/news-composer.config";
// post config — modeled + deferred (clamp proof; ships behind media-editor v0.2).
export { postComposerConfig } from "./configs/post-composer.config";
export { getAdapter, ADAPTER_REGISTRY } from "./adapters/adapter-registry";

// Public type surface (description §9/§10). Implementation-internal hooks +
// substrate records (useComposerState, default substrates, findSubstrate, …)
// are added to this barrel as they land across the C3–C12 chain.
export type {
  // Component
  ContentComposer01Props,
  ContentComposer01Handle,
  // Config + steps
  ComposerConfig,
  ComposerStep,
  StepValidation,
  StepValidationRule,
  SlotKind,
  MetadataSlotConfig,
  BodySlotConfig,
  MediaSlotConfig,
  MediaCarouselSlotConfig,
  // Draft + values
  ComposerDraft,
  ComposerStepValue,
  BodySlotValue,
  MediaSlotValue,
  MediaCarouselSlotValue,
  MediaCarouselItemRef,
  SerializableMediaEditorState,
  // Substrate registry
  SlotSubstrate,
  SlotSubstrateMap,
  SlotRenderArgs,
  SlotHandle,
  SlotConfigFor,
  SlotValueFor,
  // Adapter
  ContentTypeAdapter,
  AdapterRegistry,
  // Lifecycle
  PublishMode,
  PublishIntent,
  ComposerPhase,
  GateResult,
  // Context
  ComposerCtx,
  ComposerStepCtx,
  // Hook + helper signatures
  UseComposerStateArgs,
  UseComposerContext,
  UseComposerStep,
  FindSubstrate,
  // Re-exported substrate types
  ContentCardItem,
  ArticleBodyValue,
  InitialSource,
  ExportMetadata,
  MediaEditorState,
} from "./types";

import type { ReactNode, Ref } from "react";
import type {
  MediaEditor01Props,
  MediaEditor01Handle,
  MediaEditorState,
  ExportMetadata,
  InitialSource,
  ComposerMode,
  EditTool,
  MediaSource,
  AspectRatio,
} from "@/registry/components/media/media-editor-01/media-editor-01";
import type { ArticleBodyValue } from "@/registry/components/data/article-body-01/article-body-01";
import type {
  ContentCardItem,
  ContentStatus,
  NewsArticleAuthor,
  NewsPublisher,
  NewsVisibility,
  ContentSensitivity,
  ContentPaywall,
} from "@/registry/components/data/content-card-news-01/content-card-news-01";
import type { FormSchema, Condition } from "@/registry/components/forms/json-form/json-form";

// Re-export the substrate types the public surface leans on, so consumers
// import them from the content-composer barrel without reaching into the
// substrate procomps directly. Centralizing the content-card-news-01 type
// import here keeps the cross-procomp `/types` reference in ONE place (the
// config + adapter then read these via the local barrel, not cross-procomp).
export type { MediaEditorState, ExportMetadata, InitialSource, ArticleBodyValue, ContentCardItem, ContentStatus };
export type { MediaEditor01Props, MediaEditor01Handle };
export type {
  NewsArticleAuthor,
  NewsPublisher,
  NewsVisibility,
  ContentSensitivity,
  ContentPaywall,
};

// ─── Slot kinds + config (description §15) ──────────────────────────────

export type SlotKind =
  | "metadataFields"
  | "bodySlot"
  | "mediaSlot"
  | "mediaCarouselSlot";

export interface ComposerConfig {
  /** "news" | "post" | "event" | "project" */
  id: string;
  /** config schema version (semver) */
  version: string;
  title: string;
  /** runtime adapter-registry key */
  adapterId: string;
  steps: ComposerStep[];
  /** subset of ["draft","publish","schedule"] */
  publishModes: PublishMode[];
  presentation?: "inline" | "dialog" | "auto";
  autosave?: { enabled: boolean; debounceMs?: number };
}

export interface ComposerStep {
  id: string;
  title: string;
  /** substrate-registry lookup key */
  slot: SlotKind;
  /** discriminated by `slot` at the consumer site (JSON — no TS narrowing) */
  slotConfig:
    | MetadataSlotConfig
    | BodySlotConfig
    | MediaSlotConfig
    | MediaCarouselSlotConfig;
  /** BLOCKING gate before advance/publish */
  validation?: StepValidation;
  optional?: boolean;
  /** json-form Condition DSL, reused for whole-step visibility (serializable object form only) */
  visibleWhen?: Condition;
}

export interface StepValidationRule {
  field: string;
  /** bodySlot: min Plate/plaintext length */
  minLength?: number;
  /** mediaSlot: require a hero (exportedUrl present OR dirty) */
  mediaRequired?: boolean;
  message: string;
}

export interface StepValidation {
  /**
   * "all-fields-valid" → delegate to json-form trigger(); "custom" → run `rules`.
   * NOTE: advisory for metadataFields steps — a metadata slot can only validate via
   * trigger()+isValid(), so `mode` there is effectively "all-fields-valid" and a
   * `custom` rule declared on a metadata step is ignored. `custom`+`rules` change
   * behavior only for bodySlot (minLength) and mediaSlot (mediaRequired) steps.
   */
  mode: "all-fields-valid" | "custom";
  rules?: StepValidationRule[];
}

// ─── The three discriminated slot configs (description §4) ──────────────

/** metadataFields → a json-form FormSchema fragment. */
export interface MetadataSlotConfig {
  columns?: 1 | 2;
  /** { fields: FieldDefinition[] } fragment */
  schema: FormSchema;
}

/** bodySlot → article-body-01 (Plate) OR shadcn <Textarea> plaintext fallback. */
export interface BodySlotConfig {
  substrate: "plate" | "plaintext";
  fieldName: string;
  placeholder?: string;
  /** plate-only sentinel; plaintext ignores it and uses "" — defaults to ARTICLE_BODY_EMPTY_VALUE */
  emptyValue?: ArticleBodyValue;
}

/**
 * mediaSlot → 1:1 passthrough of media-editor-01's dials. Every key is a verified
 * MediaEditor01Props prop. The shell spreads these straight onto <MediaEditor01>,
 * EXCEPT `mediaSources` which the substrate CLAMPS to the real MediaSource union
 * before spreading (drops not-yet-valid "library" — §clamp).
 */
export interface MediaSlotConfig {
  fieldName: string;
  enabledModes: ComposerMode[];
  enabledTools: EditTool[];
  /** broad so a config can declare "library" ahead of media-editor v0.2; the substrate clamps it. */
  mediaSources: (MediaSource | (string & {}))[];
  aspect: AspectRatio;
  /** default "inline" inside the composer (§2) */
  presentation?: "inline" | "dialog" | "auto";
  cropAspects?: AspectRatio[];
  maxFileSizeMb?: number;
}

// ─── Body value + draft (description §6) — JSON-clean, NO blob ───────────

/** The asymmetry the SlotHandle hides: richtext = ArticleBodyValue (Plate node array); plaintext = string. */
export type BodySlotValue =
  | { kind: "richtext"; value: ArticleBodyValue }
  | { kind: "plaintext"; value: string };

/**
 * MediaEditorState minus the non-serializable live Blob (videoBlob: Blob). The draft
 * persists THIS, never the raw MediaEditorState. On re-edit the shell re-attaches the
 * blob from its Map (or re-fetches from exportedUrl) before calling handle.loadState().
 */
export type SerializableMediaEditorState = Omit<MediaEditorState, "videoBlob"> & {
  videoBlob: null;
};

export interface MediaSlotValue {
  /** durable uploaded https URL (post-upload) — the persistable handle */
  exportedUrl?: string;
  /** transient key into the shell-held Map<string,Blob>; consumed once at upload */
  pendingBlobRef?: string;
  /** .metadata leg of export() */
  exportMetadata?: ExportMetadata;
  /** blob-free editor snapshot for re-edit */
  editorState?: SerializableMediaEditorState;
}

// ─── mediaCarouselSlot (content-composer v0.2) ──────────────────────────
// A multi-item media step backed by media-carousel-editor-01. The post config
// uses this instead of the single mediaSlot. `news` keeps the single mediaSlot
// — this kind is strictly additive.

/** mediaCarouselSlot → media-carousel-editor-01 dials (subset). */
export interface MediaCarouselSlotConfig {
  fieldName: string;
  /** default 10 (Instagram parity). */
  maxItems?: number;
  maxFileSizeMb?: number;
  /** default ["image","video"]. */
  accept?: ("image" | "video")[];
  /** "auto" derives the shared aspect from item 1. Default "auto". */
  aspect?: AspectRatio | "auto";
  /** forwarded to the per-item edit panel. */
  enabledTools?: EditTool[];
}

/**
 * One serializable carousel item in the draft (NO blob — JSON-clean, mirroring
 * MediaSlotValue). Local (not-yet-uploaded) items carry `editorState` but no
 * `exportedUrl`; the durable upload-at-publish of N blobs rides with the post
 * backend adapter (deferred, same as the single mediaSlot's `"library"` source).
 */
export interface MediaCarouselItemRef {
  id: string;
  kind: "image" | "video";
  /** durable https URL once uploaded / when re-edit-seeded from the backend. */
  exportedUrl?: string;
  /** blob-free editor snapshot for re-edit (photo path). */
  editorState?: SerializableMediaEditorState;
  exportMetadata?: ExportMetadata;
}

export interface MediaCarouselSlotValue {
  items: MediaCarouselItemRef[];
}

export type ComposerStepValue =
  | { slot: "metadataFields"; value: Record<string, unknown> }
  | { slot: "bodySlot"; value: BodySlotValue }
  | { slot: "mediaSlot"; value: MediaSlotValue }
  | { slot: "mediaCarouselSlot"; value: MediaCarouselSlotValue };

export interface ComposerDraft {
  contentType: string;
  /** keyed by step id; discriminated by slot kind */
  steps: Record<string, ComposerStepValue>;
  /** "draft"|"scheduled"|"published"|"archived" → ContentCardItem.status (same CLOSED enum) */
  status: ContentStatus;
  /** ISO; set by the schedule arm */
  scheduledFor?: string;
  /** set on first publish; preserved on re-edit so a PATCH targets the row */
  contentId?: string;
  /** PERSISTED so re-open resumes the step */
  cursor: number;
}

// ─── Substrate registry + render args (description §3) ──────────────────

export type SlotConfigFor<K extends SlotKind> = K extends "metadataFields"
  ? MetadataSlotConfig
  : K extends "bodySlot"
    ? BodySlotConfig
    : K extends "mediaSlot"
      ? MediaSlotConfig
      : K extends "mediaCarouselSlot"
        ? MediaCarouselSlotConfig
        : never;

export type SlotValueFor<K extends SlotKind> = K extends "metadataFields"
  ? Record<string, unknown>
  : K extends "bodySlot"
    ? BodySlotValue
    : K extends "mediaSlot"
      ? MediaSlotValue
      : K extends "mediaCarouselSlot"
        ? MediaCarouselSlotValue
        : never;

export interface SlotRenderArgs<K extends SlotKind = SlotKind> {
  slotConfig: SlotConfigFor<K>;
  value: SlotValueFor<K> | undefined;
  onChange: (next: SlotValueFor<K>) => void;
  ctx: ComposerStepCtx;
  /** the shell threads a ref the substrate populates with a uniform SlotHandle */
  handleRef: Ref<SlotHandle<SlotValueFor<K>>>;
}

export interface SlotSubstrate<K extends SlotKind = SlotKind> {
  kind: K;
  render: (args: SlotRenderArgs<K>) => ReactNode;
}

/** Strongly-typed map keyed by the 3 closed kinds (NOT Map<string,Any> like kanban). */
export type SlotSubstrateMap = Partial<{ [K in SlotKind]: SlotSubstrate<K> }>;

// ─── SlotHandle (description §3/§9) — uniform across all three slots ─────

export interface SlotHandle<TValue = unknown> {
  /** current slot value for the ComposerDraft snapshot */
  getValue: () => TValue;
  /** aggregated into the shell's OR-of-three dirty */
  getIsDirty: () => boolean;
  /** BLOCKING gate primitive (QP-9). metadata → await trigger() then isValid() */
  validate: () => Promise<boolean>;
  /** re-seed on autosave-restore / re-edit. RESETS the dirty baseline */
  loadValue: (value: TValue) => void;
  /**
   * mediaSlot ONLY — pull-only export so the shell can upload the captured hero
   * at publish/schedule (QP-10 lazy upload). Other slots omit it; the shell
   * duck-types its presence.
   */
  export?: () => Promise<{ blob: Blob; metadata: ExportMetadata }>;
}

// ─── Adapter (description §5) — pure forward+inverse fns, NOT components ──

export interface ContentTypeAdapter<TItem> {
  contentType: string;
  toContentItem: (
    draft: ComposerDraft,
    ctx: { now: Date; currentUser?: { id: string; name: string } },
  ) => TItem;
  fromContentItem: (item: TItem) => {
    draft: Partial<ComposerDraft>;
    mediaInitialSource?: InitialSource;
  };
}

export type AdapterRegistry = Record<string, ContentTypeAdapter<ContentCardItem>>;

// ─── Publish intent + FSM surface (description §7) ──────────────────────

export type PublishMode = "draft" | "publish" | "schedule";

export type PublishIntent =
  | { mode: "draft" }
  | { mode: "publish" }
  | { mode: "schedule"; publishAt: Date };

export type ComposerPhase =
  | "idle"
  | "editing"
  | "autosaving"
  | "validating"
  | "draft-saved"
  | "scheduling"
  | "scheduled"
  | "publishing"
  | "published"
  | "publish-error";

export interface GateResult {
  ok: boolean;
  firstInvalidStepId?: string;
  firstInvalidField?: string;
  /** per-step error messages */
  errors?: Record<string, string[]>;
}

// ─── Per-mount context (description §10) — workspace useAreaContext model ─

export interface ComposerCtx {
  contentType: string;
  phase: ComposerPhase;
  cursor: number;
  steps: ComposerStep[];
  isDirty: boolean;
  stepErrors: Record<string, string[]>;
  publishModes: PublishMode[];
  goToStep: (n: number) => Promise<GateResult>;
  saveDraft: () => Promise<void>;
  publish: () => Promise<void>;
  schedule: (at: Date) => Promise<void>;
}

/** Returned by useComposerStep() — throws outside a step subtree. */
export interface ComposerStepCtx {
  stepId: string;
  contentType: string;
  mode: "inline" | "dialog";
  isDirty: boolean;
  stepErrors: string[];
}

// ─── Public component props + handle (description §9) ───────────────────

export interface ContentComposer01Props {
  // The config (JSON)
  config: ComposerConfig;
  /** defaults shipped + spreadable + overridable */
  substrates?: SlotSubstrateMap;

  // Re-edit
  /** drives the INVERSE adapter (item.image → media initialSource) */
  initialItem?: ContentCardItem;
  /** persisted body — NOT on ContentCardItem (§5) */
  initialBody?: BodySlotValue;

  // Presentation
  presentation?: "inline" | "dialog" | "auto";
  isOpen?: boolean;
  onClose?: () => void;

  // Draft state (controlled triplet — copy useKanbanState)
  value?: ComposerDraft;
  defaultValue?: ComposerDraft;
  onChange?: (draft: ComposerDraft) => void;

  // Autosave (split: per-mutation vs debounced — QP-4)
  autosave?: boolean;
  /** per mutation */
  onDraftChange?: (draft: ComposerDraft) => void;
  /** debounced (~800ms) */
  onAutosave?: (draft: ComposerDraft) => void | Promise<void>;

  // Lifecycle exits (emit the assembled ContentItem; affordance-gated by callback presence)
  onSaveDraft?: (item: ContentCardItem) => void | Promise<void>;
  onPublish?: (item: ContentCardItem) => void | Promise<void>;
  onSchedule?: (item: ContentCardItem, publishAt: Date) => void | Promise<void>;

  // The SHELL owns upload (DELTA vs media-editor-01 — QP-8)
  /** primary upload contract */
  uploader?: (blob: Blob, meta: ExportMetadata) => Promise<{ url: string }>;
  /** convenience shorthand */
  uploadUrl?: string;

  // Slots (escape hatches)
  renderPublishCTA?: (ctx: ComposerCtx) => ReactNode;
  renderStepChrome?: (ctx: ComposerCtx) => ReactNode;

  ref?: Ref<ContentComposer01Handle>;
}

export interface ContentComposer01Handle {
  saveDraft(): Promise<void>;
  publish(): Promise<void>;
  schedule(at: Date): Promise<void>;
  goToStep(n: number): Promise<GateResult>;
  getIsDirty(): boolean;
  getDraft(): ComposerDraft;
  loadDraft(draft: ComposerDraft): void;
}

// ─── Exported hook + helper signatures (description §10) ─────────────────

export interface UseComposerStateArgs {
  contentType: string;
  value?: ComposerDraft;
  defaultValue?: ComposerDraft;
  /** === onDraftChange (per-mutation, both modes) */
  onChange?: (next: ComposerDraft) => void;
}

/** throws outside the composer subtree */
export type UseComposerContext = () => ComposerCtx;
/** throws outside a step subtree */
export type UseComposerStep = () => ComposerStepCtx;
export type FindSubstrate = <K extends SlotKind>(
  substrates: SlotSubstrateMap,
  key: K,
) => SlotSubstrate<K> | undefined;

import type {
  AdapterRegistry,
  ContentCardItem,
  ContentTypeAdapter,
