      },
      [NEWS_STEP.hero]: {
        slot: "mediaSlot",
        value: { exportedUrl: item.image },
      },
      // NO body step — the body re-seeds via the separate initialBody leg.
    },
  };
  return { draft, mediaInitialSource: { kind: "url", url: item.image, mode: "photo" } };
