import { useCallback, useEffect, useRef, useState } from "react";
import type { ComposerDraft, ComposerPhase } from "../types";
import type { PhaseAction } from "../lib/phase-reducer";

export interface UseAutosaveArgs {
  draft: ComposerDraft;
  phase: ComposerPhase;
  /** false disables autosave (affordance-gate); default true */
  autosave?: boolean;
  onAutosave?: (draft: ComposerDraft) => void | Promise<void>;
  debounceMs?: number;
  dispatchPhase: (action: PhaseAction) => void;
}

export interface UseAutosaveReturn {
  /** draft-level dirty — true iff the draft differs from the last saved snapshot */
  isDirty: boolean;
  /** mark a draft saved (called by explicit saveDraft / publish so autosave doesn't re-fire) */
  markSaved: (draft: ComposerDraft) => void;
}

/**
 * Debounced autosave (QP-4). The split is structural: `onDraftChange` is the
 * per-mutation callback inside `useComposerState` dispatch; THIS is the
 * downstream debounced effect watching the draft.
 *
 * Dirty is DRAFT-LEVEL (`draft !== savedDraft`) — every slot mutation flows into
 * the draft via per-mutation `onChange`, so the draft is the single dirty
 * signal. This both is correct for single-step mounting (only the active slot
 * is mounted) and structurally averts the Plate autosave loop (no handle-
 * aggregate-dirty to mis-baseline). After a successful autosave the saved
 * snapshot advances, so a settled idle draft never re-fires.
 */
export function useAutosave({
  draft,
  phase,
  autosave,
  onAutosave,
  debounceMs,
  dispatchPhase,
}: UseAutosaveArgs): UseAutosaveReturn {
  // savedDraft is STATE (render-safe) so `isDirty` is a clean render value.
  const [savedDraft, setSavedDraft] = useState<ComposerDraft>(draft);
  const isDirty = draft !== savedDraft;

  const onAutosaveRef = useRef(onAutosave);
  useEffect(() => {
    onAutosaveRef.current = onAutosave;
  }, [onAutosave]);

  // fire-time phase guard — closes the React-batching window where a Publish/
  // Schedule could flip phase between the timer firing and the cleanup running.
  const phaseRef = useRef(phase);
  useEffect(() => {
    phaseRef.current = phase;
  }, [phase]);

  useEffect(() => {
    if (autosave === false || !onAutosaveRef.current) return; // affordance-gate
    if (phase !== "editing" && phase !== "draft-saved") return; // only while editing/draft
    if (draft === savedDraft) return; // dirty-gated (draft-level)

    const ms = debounceMs ?? 800;
    const id = setTimeout(async () => {
      if (phaseRef.current !== "editing" && phaseRef.current !== "draft-saved") {
        return;
      }
      const snapshot = draft;
      dispatchPhase({ type: "autosave-begin" }); // T5
      try {
        await onAutosaveRef.current?.(snapshot);
        setSavedDraft(snapshot); // advance the saved baseline → settles dirty
      } finally {
        dispatchPhase({ type: "autosave-end" }); // T6
      }
    }, ms);
    return () => clearTimeout(id);
  }, [draft, savedDraft, phase, autosave, debounceMs, dispatchPhase]);

  const markSaved = useCallback((d: ComposerDraft) => setSavedDraft(d), []);

  return { isDirty, markSaved };
}

"use client";

import { useCallback, useEffect, useRef } from "react";
import { ARTICLE_BODY_EMPTY_VALUE } from "@/registry/components/data/article-body-01/article-body-01";
import type { BodySlotConfig, BodySlotValue } from "../types";

/**
 * Stable content key for a body value. `<ArticleBodyEditor>` (Plate) exposes NO
 * dirty signal, so the shell derives bodySlot dirty by baseline JSON-compare
 * over this key. Plate JSON has no functions/cycles, so `JSON.stringify` is
 * adequate; over-sync (never skip) on the cycle edge.
 */
export function bodyContentKey(v: BodySlotValue): string {
  try {
    return v.kind === "plaintext" ? `p:${v.value}` : `r:${JSON.stringify(v.value)}`;
  } catch {
    return `x:${Math.random()}`;
  }
}

/** Flattened plain text of a body value (Plate node tree → text, or the raw string). */
export function flattenPlainText(v: BodySlotValue): string {
  if (v.kind === "plaintext") return v.value;
  let out = "";
  const walk = (n: unknown) => {
    if (n && typeof n === "object") {
      const node = n as { text?: unknown; children?: unknown };
      if (typeof node.text === "string") out += node.text;
      if (Array.isArray(node.children)) node.children.forEach(walk);
    }
  };
  if (Array.isArray(v.value)) v.value.forEach(walk);
  return out;
}

/** Empty = no non-whitespace flattened text (covers both substrates + the empty sentinel). */
export function isBodyEmpty(v: BodySlotValue): boolean {
  return flattenPlainText(v).trim().length === 0;
}

/** The CONFIGURED minLength gate (used shell-side in evaluateStepGate). */
export function bodyMinLengthValid(v: BodySlotValue, minLength: number): boolean {
  return flattenPlainText(v).trim().length >= minLength;
}

/** The empty value for a body slot, per its substrate. */
export function defaultBodyValue(slotConfig: BodySlotConfig): BodySlotValue {
  return slotConfig.substrate === "plaintext"
    ? { kind: "plaintext", value: "" }
    : {
        kind: "richtext",
        value: slotConfig.emptyValue ?? ARTICLE_BODY_EMPTY_VALUE,
      };
}

/**
 * Baseline-compare dirty tracking for a body slot (#1 implementation trap).
 *
 * The `baselineRef` MUST reset after every successful save/autosave AND on
 * `loadValue()` — otherwise the body reports permanently-dirty, the aggregate
 * dirty stays true, and autosave loops forever. `rebaseline()` is the reset.
 */
export function useBodyDirty(current: BodySlotValue) {
  const valueRef = useRef(current);
  useEffect(() => {
    valueRef.current = current;
  });

  const baselineRef = useRef(bodyContentKey(current));

  const getIsDirty = useCallback(
    () => bodyContentKey(valueRef.current) !== baselineRef.current,
    [],
  );
  const rebaseline = useCallback((v?: BodySlotValue) => {
    baselineRef.current = bodyContentKey(v ?? valueRef.current);
  }, []);

  return { valueRef, getIsDirty, rebaseline };
}

