import { createContext, useContext } from "react";
import type { ComposerCtx, ComposerStepCtx } from "../types";

// Two contexts (workspace useAreaContext model): the per-mount composer context
// (phase / cursor / steps / lifecycle actions) and the per-step context (active
// step id + its error slice). Both throw when read outside their subtree so a
// mis-mounted custom field/slot fails loudly rather than silently no-op-ing.

export const ComposerContext = createContext<ComposerCtx | null>(null);
export const ComposerStepContext = createContext<ComposerStepCtx | null>(null);

export function useComposerContext(): ComposerCtx {
  const ctx = useContext(ComposerContext);
  if (!ctx) {
    throw new Error(
      "useComposerContext must be called inside a <ContentComposer01> subtree",
    );
  }
  return ctx;
}

export function useComposerStep(): ComposerStepCtx {
  const ctx = useContext(ComposerStepContext);
  if (!ctx) {
    throw new Error(
      "useComposerStep must be called inside a composer step's slot subtree",
    );
  }
  return ctx;
}

"use client";

import * as React from "react";
import type {
  ComposerDraft,
  ComposerPhase,
  UseComposerStateArgs,
} from "../types";
import { composerReducer, makeEmptyDraft, type ComposerAction } from "../lib/reducer";
import { phaseReducer, type PhaseAction } from "../lib/phase-reducer";

export interface UseComposerStateReturn {
  draft: ComposerDraft;
  dispatch: (action: ComposerAction) => void;
  phase: ComposerPhase;
  dispatchPhase: (action: PhaseAction) => void;
}

/**
 * The controlled/uncontrolled draft triplet + the ephemeral FSM phase. A
 * verbatim fork of kanban-board-01's `useKanbanState`:
 *   - an internal reducer is ALWAYS kept (used only when uncontrolled);
 *   - `dispatch` reduces over the DERIVED draft (not `internal`) for
 *     controlled-mode correctness, and always fires the per-mutation
 *     `onChange` (= `onDraftChange`) in BOTH modes;
 *   - the FSM phase is a SEPARATE reducer so the draft stays pure JSON (§6).
 */
export function useComposerState({
  contentType,
  value,
  defaultValue,
  onChange,
}: UseComposerStateArgs): UseComposerStateReturn {
  // ALWAYS keep an internal reducer (kanban pattern) — used only when uncontrolled.
  const [internal, internalDispatch] = React.useReducer(
    composerReducer,
    defaultValue ?? makeEmptyDraft(contentType),
  );
  const isControlled = value !== undefined;
  const draft = value ?? internal; // === isControlled ? value : internal, type-safe

  // latest-onChange ref — stable dispatch identity across parent re-renders.
  const onChangeRef = React.useRef(onChange);
  React.useEffect(() => {
    onChangeRef.current = onChange;
  });

  const dispatch = React.useCallback(
    (action: ComposerAction) => {
      // GOTCHA: reduce over the DERIVED draft, NOT `internal` — controlled-mode correctness.
      const next = composerReducer(value ?? internal, action);
      if (!isControlled) internalDispatch(action); // internal store only when uncontrolled
      onChangeRef.current?.(next); // per-mutation onDraftChange — BOTH modes
    },
    [isControlled, value, internal],
  );

  // ephemeral FSM phase — NOT persisted (kept out of ComposerDraft, §6).
  const [phase, dispatchPhase] = React.useReducer(
    phaseReducer,
    "idle" as ComposerPhase,
  );

  return { draft, dispatch, phase, dispatchPhase };
}

"use client";

import { useCallback, useRef } from "react";
import type { RefCallback } from "react";
import type { SlotHandle } from "../types";

/**
 * Registry of the live `SlotHandle`s keyed by step id. The shell renders only
 * the ACTIVE step's slot, so at any moment the map holds one entry (the active
 * step's handle). The shell reads it for the active-step gate (full json-form
 * validation) and for the pull-only media export at step-leave / publish.
 *
 * `registerHandle(stepId)` returns a STABLE callback ref per step id (so React
 * doesn't detach/reattach on every render). Dirty tracking is intentionally NOT
 * here — it's draft-level (`draft !== savedDraft` in useAutosave), which both is
 * correct for single-step mounting and structurally averts the Plate autosave
 * loop (the handle-aggregate-dirty trap).
 */
export function useSlotHandles() {
  const handles = useRef(new Map<string, SlotHandle<unknown>>());
  const callbacks = useRef(new Map<string, RefCallback<SlotHandle<unknown>>>());

  const registerHandle = useCallback(
    (stepId: string): RefCallback<SlotHandle<unknown>> => {
      let cb = callbacks.current.get(stepId);
      if (!cb) {
        cb = (h) => {
          if (h) handles.current.set(stepId, h);
          else handles.current.delete(stepId);
        };
        callbacks.current.set(stepId, cb);
      }
      return cb;
    },
    [],
  );

  const getHandle = useCallback(
    (stepId: string) => handles.current.get(stepId),
    [],
  );

  return { registerHandle, getHandle };
}

import type { Ref, RefCallback } from "react";

/**
 * Assign a value to a React ref in either form. Substrate mounts capture their
 * uniform `SlotHandle` into the shell-provided `handleRef` (typed `Ref<…>`,
 * which can be a callback or an object ref), so they go through this helper
 * rather than assuming `.current`.
 */
export function assignRef<T>(ref: Ref<T> | undefined, value: T): void {
  if (typeof ref === "function") {
    (ref as RefCallback<T>)(value);
  } else if (ref) {
    (ref as { current: T }).current = value;
  }
}

import type { MediaSource } from "@/registry/components/media/media-editor-01/media-editor-01";

const KNOWN: readonly MediaSource[] = ["camera", "upload"];

/**
 * Drop any mediaSource media-editor-01 v0.1.x doesn't understand (e.g.
 * `"library"`, which a `post` config declares ahead of media-editor-01 v0.2).
 * Never throws — mirrors the dial's own no-crash membership-only degradation.
 * Falls back to `["upload"]` if the filtered set is empty so the slot is never
 * sourceless. The ONLY transformed dial — every other dial is membership-
 * filtered inside media-editor, so over-declared arrays degrade the same way.
 */
export function clampMediaSources(
  declared: readonly string[] | undefined,
): MediaSource[] {
  const known = (declared ?? KNOWN).filter(
    (s): s is MediaSource => s === "camera" || s === "upload",
  );
  return known.length ? known : ["upload"];
}

import type { FormSchema } from "@/registry/components/forms/json-form/json-form";
import { evaluateCondition } from "@/registry/components/forms/json-form/lib/condition-evaluator";
import { getByPath } from "@/registry/components/forms/json-form/lib/path";
import type {
  BodySlotValue,
  ComposerConfig,
  ComposerDraft,
  ComposerStep,
  GateResult,
  MediaCarouselSlotValue,
  MediaSlotValue,
  MetadataSlotConfig,
  SlotHandle,
  StepValidation,
} from "../types";
import { bodyMinLengthValid, isBodyEmpty } from "../hooks/use-body-dirty";

/**
 * Config-sourced BLOCKING gates (QP-9), evaluated imperatively at advance/
 * publish. Forward-gated / backward-free. DISTINCT from the non-blocking
 * missing-substrate fallback.
 *
 * Gate decisions run against the persisted draft values — the draft is ALWAYS
 * current (per-mutation onChange), and the news config has THREE metadataFields
 * steps so only the active step is ever mounted. For the active metadata step
 * the live handle's full json-form validation is preferred (catches pattern/
 * custom validators, not just required-presence); non-active steps fall back to
 * the value-based required-presence check (they were fully validated when the
 * user last left them forward).
 */

/** Compile-time exhaustiveness: a new SlotKind without a switch arm fails here. */
function assertNever(value: never): void {
  void value; // purely a type-level guard — no runtime effect
}

function isValueEmpty(v: unknown): boolean {
  if (v == null) return true;
  if (typeof v === "string") return v.trim().length === 0;
  if (Array.isArray(v)) return v.length === 0;
  return false;
}

/** Merge every metadataFields step's value bag — the values namespace shared by
 *  step-level visibleWhen conditions. */
export function aggregateMetaValues(draft: ComposerDraft): Record<string, unknown> {
  const out: Record<string, unknown> = {};
  for (const sv of Object.values(draft.steps)) {
    if (sv.slot === "metadataFields") Object.assign(out, sv.value);
  }
  return out;
}

/** Headless required-presence check (the value-based metadata gate). */
export function evaluateMetadataValue(
  schema: FormSchema,
  value: Record<string, unknown>,
): boolean {
  for (const f of schema.fields) {
    if (f.type === "section" || f.type === "divider" || f.type === "hidden") {
      continue;
    }
    if (!f.validators?.required) continue;
    if (isValueEmpty(getByPath(value, f.name))) return false;
  }
  return true;
}

export function evaluateBodyValue(
  value: BodySlotValue | undefined,
  validation: StepValidation | undefined,
): boolean {
  const rule = validation?.rules?.find((r) => r.minLength != null);
  if (!rule?.minLength) return true;
  if (!value) return false;
  return bodyMinLengthValid(value, rule.minLength);
}

export function evaluateMediaValue(
  value: MediaSlotValue | undefined,
  validation: StepValidation | undefined,
  isDirty: boolean,
): boolean {
  if (!validation?.rules?.some((r) => r.mediaRequired)) return true;
  return !!value?.exportedUrl || isDirty;
}

/** mediaCarouselSlot gate — value-based (the draft is always current). When
 *  `mediaRequired`, at least one item must be present. */
export function evaluateMediaCarouselValue(
  value: MediaCarouselSlotValue | undefined,
  validation: StepValidation | undefined,
): boolean {
  if (!validation?.rules?.some((r) => r.mediaRequired)) return true;
  return (value?.items?.length ?? 0) > 0;
}

/** Whole-step visibility (serializable Condition object form only). */
export function isStepVisible(
  step: ComposerStep,
  allValues: Record<string, unknown>,
): boolean {
  if (!step.visibleWhen) return true;
  return evaluateCondition(step.visibleWhen, allValues);
}

/** Is the step empty (for optional-skip)? */
export function isStepEmpty(step: ComposerStep, draft: ComposerDraft): boolean {
  const sv = draft.steps[step.id];
  if (!sv) return true;
  switch (sv.slot) {
    case "metadataFields":
      return (
        Object.keys(sv.value).length === 0 ||
        Object.values(sv.value).every(isValueEmpty)
      );
    case "bodySlot":
      return isBodyEmpty(sv.value);
    case "mediaSlot":
      return !sv.value.exportedUrl && !sv.value.editorState;
    case "mediaCarouselSlot":
      return (sv.value.items?.length ?? 0) === 0;
    default:
      assertNever(sv);
      return true;
  }
}

/**
 * Evaluate a single step's blocking gate. `activeHandle` is supplied ONLY for
 * the currently-mounted step (so metadata gets full json-form validation +
 * media gets live dirty); non-mounted steps validate against stored values.
 */
export async function evaluateStep(
  config: ComposerConfig,
  stepIndex: number,
  draft: ComposerDraft,
  opts: { activeHandle?: SlotHandle<unknown> } = {},
): Promise<GateResult> {
  const step = config.steps[stepIndex];
  if (!step) return { ok: true };

  // Hidden step → skip the gate (NON-blocking).
  if (!isStepVisible(step, aggregateMetaValues(draft))) return { ok: true };
  // Optional + untouched → pass.
  if (step.optional && isStepEmpty(step, draft)) return { ok: true };

  const sv = draft.steps[step.id];
  const fail = (): GateResult => ({ ok: false, firstInvalidStepId: step.id });

  switch (step.slot) {
    case "metadataFields": {
      if (opts.activeHandle) {
        // Active mounted step → full json-form validation (trigger + isValid),
        // which also surfaces inline field errors as a side effect.
        return (await opts.activeHandle.validate()) ? { ok: true } : fail();
      }
      const schema = (step.slotConfig as MetadataSlotConfig).schema;
      const value = sv?.slot === "metadataFields" ? sv.value : {};
      return evaluateMetadataValue(schema, value) ? { ok: true } : fail();
    }
    case "bodySlot": {
      const value = sv?.slot === "bodySlot" ? sv.value : undefined;
      return evaluateBodyValue(value, step.validation) ? { ok: true } : fail();
    }
    case "mediaSlot": {
      const value = sv?.slot === "mediaSlot" ? sv.value : undefined;
      const isDirty = opts.activeHandle?.getIsDirty() ?? false;
      return evaluateMediaValue(value, step.validation, isDirty)
        ? { ok: true }
        : fail();
    }
    case "mediaCarouselSlot": {
      const value = sv?.slot === "mediaCarouselSlot" ? sv.value : undefined;
      return evaluateMediaCarouselValue(value, step.validation)
        ? { ok: true }
        : fail();
    }
    default:
      assertNever(step.slot);
      return { ok: true };
  }
}

import type {
  FieldDefinition,
  FormSchema,
  FieldOptionsResolver,
} from "@/registry/components/forms/json-form/json-form";

/**
 * Config hydration layer (QP-6). A `ComposerConfig` stays a pure `.json` file
 * only while its json-form fragment is purely declarative. Function-valued
 * escape-hatches (`validate` / `validateAsync` / `compute` / async `options` /
 * the FN arm of `visibleWhen`/`enabledWhen`/`requiredWhen`) can't live in JSON.
 * This layer re-attaches them onto a deserialized `FormSchema` (by field name)
 * BEFORE the schema reaches `<JsonForm>`, and strips them back out to recover
 * the pure JSON shape (round-trip invariant).
 *
 * The OBJECT form of a `Condition` survives JSON, so `visibleWhen` etc. only
 * need hydration when authored as a function. `expression` (string) survives;
 * `compute` is its fn escape-hatch.
 *
 * The news v0.1 config needs ZERO hydration entries — `slug` uses
 * `expression: "{title}"` and `sensitivity.reason` uses the Condition OBJECT
 * form. The seam exists for future `post`/`event`/`project` configs.
 */

/** The fn arm of json-form's `ConditionOrFn` (the OBJECT arm survives JSON). */
export type ConditionFn = (args: { values: Record<string, unknown> }) => boolean;

export interface FieldHydration {
  validate?: FieldDefinition["validate"];
  validateAsync?: FieldDefinition["validateAsync"];
  compute?: FieldDefinition["compute"];
  options?: FieldOptionsResolver;
  visibleWhen?: ConditionFn;
  enabledWhen?: ConditionFn;
  requiredWhen?: ConditionFn;
}

export interface SchemaHydration {
  validate?: FormSchema["validate"];
  zodSchema?: FormSchema["zodSchema"];
}

export interface ComposerConfigHydration {
  /** keyed by `field.name` */
  fields: Record<string, FieldHydration>;
  __schema__?: SchemaHydration;
}

/**
 * Re-attach function escape-hatches onto a deserialized `FormSchema`, by field
 * name. Pure. Called BEFORE the schema reaches `<JsonForm>` (so RHF/Zod see the
 * real fns). Returns `plain` unchanged when there is no hydration.
 */
export function hydrateSchema(
  plain: FormSchema,
  hydration?: ComposerConfigHydration,
): FormSchema {
  if (!hydration) return plain;
  const fields = plain.fields.map((f) => {
    const h = hydration.fields[f.name];
    return h ? { ...f, ...h } : f;
  });
  const sh = hydration.__schema__;
  return {
    ...plain,
    fields,
    ...(sh?.validate ? { validate: sh.validate } : {}),
    ...(sh?.zodSchema ? { zodSchema: sh.zodSchema } : {}),
  };
}

/**
 * Inverse — strip all function keys to recover the pure JSON shape. Round-trip
 * invariant: `stripHydration(hydrateSchema(plain, h)).plain` ≡ `plain` (object-
 * form conditions + static-array options are preserved on the plain field).
 */
export function stripHydration(schema: FormSchema): {
  plain: FormSchema;
  hydration: ComposerConfigHydration;
} {
  const hydration: ComposerConfigHydration = { fields: {} };

  const plainFields: FieldDefinition[] = schema.fields.map((f) => {
    const {
      validate,
      validateAsync,
      compute,
      options,
      visibleWhen,
      enabledWhen,
      requiredWhen,
      ...rest
    } = f;

    const fh: FieldHydration = {};
    if (typeof validate === "function") fh.validate = validate;
    if (typeof validateAsync === "function") fh.validateAsync = validateAsync;
    if (typeof compute === "function") fh.compute = compute;
    if (typeof options === "function") fh.options = options;
    if (typeof visibleWhen === "function") fh.visibleWhen = visibleWhen;
    if (typeof enabledWhen === "function") fh.enabledWhen = enabledWhen;
    if (typeof requiredWhen === "function") fh.requiredWhen = requiredWhen;
    if (Object.keys(fh).length > 0) hydration.fields[f.name] = fh;

    // Carry the serializable arms back onto the plain field.
    const plainField: FieldDefinition = { ...rest };
    if (visibleWhen && typeof visibleWhen !== "function")
      plainField.visibleWhen = visibleWhen;
    if (enabledWhen && typeof enabledWhen !== "function")
      plainField.enabledWhen = enabledWhen;
    if (requiredWhen && typeof requiredWhen !== "function")
      plainField.requiredWhen = requiredWhen;
    if (options && typeof options !== "function") plainField.options = options;
    return plainField;
  });

  const sh: SchemaHydration = {};
  const { validate: schemaValidate, zodSchema, ...schemaRest } = schema;
  if (typeof schemaValidate === "function") sh.validate = schemaValidate;
  if (zodSchema) sh.zodSchema = zodSchema;
  if (sh.validate || sh.zodSchema) hydration.__schema__ = sh;

  return { plain: { ...schemaRest, fields: plainFields }, hydration };
}

import type { ComposerPhase, PublishIntent } from "../types";

/**
 * Phase reducer — the EPHEMERAL FSM phase, deliberately kept OUT of the
 * serializable `ComposerDraft` (§6 "ONE JSON-serializable draft"). Orthogonal
 * to the draft's persisted `status` axis and to the step `cursor`.
 *
 * `schedule` is NOT a separate terminal machine: one `intent-accepted` action
 * fans out to `publishing` vs `scheduling` by `PublishIntent.mode`.
 */
export type PhaseAction =
  | { type: "start" }
  | { type: "autosave-begin" }
  | { type: "autosave-end" }
  | { type: "validate-begin" }
  | { type: "gate-fail" }
  | { type: "intent-accepted"; intent: PublishIntent }
  | { type: "draft-ack" }
  | { type: "publish-resolved" }
  | { type: "schedule-resolved" }
  | { type: "publish-rejected" }
  | { type: "retry" }
  | { type: "dismiss-error" };

export function phaseReducer(
  phase: ComposerPhase,
  action: PhaseAction,
): ComposerPhase {
  switch (action.type) {
    case "start":
      return phase === "idle" ? "editing" : phase;
    case "autosave-begin":
      return phase === "editing" ? "autosaving" : phase;
    case "autosave-end":
      return phase === "autosaving" ? "editing" : phase;
    case "validate-begin":
      return phase === "editing" || phase === "publish-error"
        ? "validating"
        : phase;
    case "gate-fail":
      return phase === "validating" ? "editing" : phase;
    case "intent-accepted": {
      if (phase !== "validating") return phase;
      // schedule = publish + future publishAt; ONE action fans out — NOT a separate terminal machine.
      return action.intent.mode === "draft"
        ? "draft-saved"
        : action.intent.mode === "publish"
          ? "publishing"
          : "scheduling";
    }
    case "draft-ack":
      return phase === "draft-saved" ? "editing" : phase;
    case "publish-resolved":
      return phase === "publishing" ? "published" : phase;
    case "schedule-resolved":
      return phase === "scheduling" ? "scheduled" : phase;
    case "publish-rejected":
      return phase === "publishing" || phase === "scheduling"
        ? "publish-error"
        : phase;
    case "retry":
      return phase === "publish-error" ? "validating" : phase;
    case "dismiss-error":
      return phase === "publish-error" ? "editing" : phase;
    default: {
      const _exhaustive: never = action;
      return _exhaustive ?? phase;
    }
  }
}

import type { ComposerPhase, PublishMode } from "../types";

export interface PublishCtaArm {
  mode: PublishMode;
  label: string;
  variant: "default" | "outline" | "secondary";
  disabled: boolean;
  busy: boolean;
}

export interface ResolvePublishCtaArgs {
  publishModes: PublishMode[];
  phase: ComposerPhase;
  /** affordance-gates: only show an arm whose lifecycle callback is wired */
  hasOnSaveDraft: boolean;
  hasOnPublish: boolean;
  hasOnSchedule: boolean;
  /** a future scheduledFor is picked (the schedule arm stays disabled until then) */
  scheduleReady: boolean;
}

/**
 * Map `config.publishModes` → the publish-bar arms. Each arm is shown only when
 * its lifecycle callback is wired (affordance-gate), disabled while a conflicting
 * phase is in flight, and `busy` while its own action runs. The schedule arm
 * also waits on a future `scheduledFor`.
 */
export function resolvePublishCtaArms({
  publishModes,
  phase,
  hasOnSaveDraft,
  hasOnPublish,
  hasOnSchedule,
  scheduleReady,
}: ResolvePublishCtaArgs): PublishCtaArm[] {
  const inFlight =
    phase === "validating" ||
    phase === "publishing" ||
    phase === "scheduling" ||
    phase === "autosaving";
  const arms: PublishCtaArm[] = [];

  if (publishModes.includes("draft") && hasOnSaveDraft) {
    arms.push({
      mode: "draft",
      label: "Save draft",
      variant: "outline",
      disabled: inFlight,
      busy: phase === "draft-saved",
    });
  }
  if (publishModes.includes("schedule") && hasOnSchedule) {
    arms.push({
      mode: "schedule",
      label: "Schedule",
      variant: "secondary",
      disabled: inFlight || !scheduleReady,
      busy: phase === "scheduling",
    });
  }
  if (publishModes.includes("publish") && hasOnPublish) {
    arms.push({
      mode: "publish",
      label: "Publish",
      variant: "default",
      disabled: inFlight,
      busy: phase === "publishing",
    });
  }
  return arms;
}

import type { ComposerDraft, ComposerStepValue, ContentStatus } from "../types";

/**
 * Draft reducer — owns the SERIALIZABLE draft only (never the ephemeral FSM
 * phase, which lives in `phase-reducer.ts`). Mirrors kanban-board-01's reducer
 * shape: a `replace` arm for full hydration/restore + targeted mutations.
 */
export type ComposerAction =
  // hydration / loadDraft / fromContentItem re-seed / autosave restore (kanban `replace` arm)
  | { type: "replace"; draft: ComposerDraft }
  // per-mutation (T4)
  | { type: "set-step-value"; stepId: string; value: ComposerStepValue }
  // cursor-under-editing (gated forward, enforced by the shell before dispatch)
  | { type: "set-cursor"; cursor: number }
  // persisted-status projection (T9/T13/T14)
  | { type: "set-status"; status: ContentStatus }
  | { type: "set-scheduled-for"; scheduledFor: string | undefined }
  | { type: "set-content-id"; contentId: string };

export function composerReducer(
  state: ComposerDraft,
  action: ComposerAction,
): ComposerDraft {
  switch (action.type) {
    case "replace":
      // full swap — no merge (kanban semantics)
      return action.draft;
    case "set-step-value":
      return {
        ...state,
        steps: { ...state.steps, [action.stepId]: action.value },
      };
    case "set-cursor":
      return state.cursor === action.cursor
        ? state
        : { ...state, cursor: action.cursor };
    case "set-status":
      return state.status === action.status
        ? state
        : { ...state, status: action.status };
    case "set-scheduled-for":
      return { ...state, scheduledFor: action.scheduledFor };
    case "set-content-id":
      return { ...state, contentId: action.contentId };
    default: {
      const _exhaustive: never = action;
      return _exhaustive ?? state;
    }
  }
}

/** kanban EMPTY analog — the uncontrolled-mode seed. */
export function makeEmptyDraft(contentType: string): ComposerDraft {
  return { contentType, steps: {}, status: "draft", cursor: 0 };
}

