import * as React from "react";
import { AlertCircle, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { cn } from "@/lib/utils";
import type { ComposerCtx } from "../types";
import { StepIndicator } from "./step-indicator";

export interface ComposerShellProps {
  ctx: ComposerCtx;
  mode: "inline" | "dialog";
  /** the mounted slot for the active step (`<SlotMount>`) */
  children: React.ReactNode;
  /** publish region (draft/publish/schedule arms) — supplied by the root at C11 */
  footer?: React.ReactNode;
  /** screen-reader announcement (gate failures, save acks) — managed by the root */
  announcement?: string;
  /** visible lifecycle error (save/publish failure) — rendered as a dismissable alert */
  error?: string | null;
  /** dismiss handler for the visible error alert */
  onDismissError?: () => void;
  /** escape hatch — extra chrome above the step body */
  renderStepChrome?: (ctx: ComposerCtx) => React.ReactNode;
  className?: string;
}

/**
 * The inline presentation frame: step nav + the active step's slot + a footer
 * with backward/forward navigation and the publish region. The root wraps the
 * `children` (the active `<SlotMount>`) in the per-step context, so this frame
 * only renders chrome. The orchestrated `reveal-up` fires once per step
 * transition (keyed on the active step id) — the single reveal per surface
 * mandated by the design system.
 */
export function ComposerShell({
  ctx,
  mode,
  children,
  footer,
  announcement,
  error,
  onDismissError,
  renderStepChrome,
  className,
}: ComposerShellProps) {
  const { steps, cursor, goToStep } = ctx;
  const step = steps[cursor];
  const isFirst = cursor <= 0;
  const isLast = cursor >= steps.length - 1;

  return (
    <div
      data-slot="composer-shell"
      data-mode={mode}
      className={cn("flex flex-col gap-4", className)}
    >
      <StepIndicator
        steps={steps}
        cursor={cursor}
        stepErrors={ctx.stepErrors}
        onStepClick={(i) => void goToStep(i)}
      />

      {renderStepChrome?.(ctx)}

      <div
        key={step?.id}
        data-composer-step-body
        className="reveal-up flex min-h-0 flex-col gap-3"
      >
        {step && (
          <h3
            id={`composer-step-${step.id}-label`}
            className="font-heading text-sm font-medium text-foreground"
          >
            {step.title}
          </h3>
        )}
        {children}
      </div>

      {/* gate-failure / save-ack announcements */}
      <div role="status" aria-live="polite" className="sr-only">
        {announcement}
      </div>

      {error ? (
        <div
          role="alert"
          className="flex items-start gap-2 rounded-md border border-destructive/40 bg-destructive/10 px-3 py-2 text-sm text-foreground"
        >
          <AlertCircle
            className="mt-0.5 size-4 shrink-0 text-destructive"
            aria-hidden
          />
          <p className="flex-1">{error}</p>
          {onDismissError ? (
            <button
              type="button"
              aria-label="Dismiss"
              onClick={onDismissError}
              className="shrink-0 rounded p-0.5 text-muted-foreground transition hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
            >
              <X className="size-4" aria-hidden />
            </button>
          ) : null}
        </div>
      ) : null}

      <Separator />

      <div className="flex items-center justify-between gap-2">
        <Button
          type="button"
          variant="ghost"
          disabled={isFirst}
          onClick={() => void goToStep(cursor - 1)}
        >
          Back
        </Button>
        <div className="flex items-center gap-2">
          {footer}
          {!isLast && (
            <Button type="button" onClick={() => void goToStep(cursor + 1)}>
              Next
            </Button>
          )}
        </div>
      </div>
    </div>
  );
}

