import { Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { cn } from "@/lib/utils";
import type { PublishCtaArm } from "../lib/publish-cta";

export interface PublishBarProps {
  arms: PublishCtaArm[];
  onSaveDraft: () => void;
  onPublish: () => void;
  onSchedule: () => void;
  /** local datetime-local string ("" until picked) */
  scheduleValue: string;
  onScheduleValueChange: (value: string) => void;
}

/**
 * Renders the resolved publish arms (`config.publishModes` → buttons). When a
 * `schedule` arm is present, a `datetime-local` input precedes the buttons; the
 * schedule arm stays disabled until a future time is picked (resolved upstream
 * via `scheduleReady`).
 */
export function PublishBar({
  arms,
  onSaveDraft,
  onPublish,
  onSchedule,
  scheduleValue,
  onScheduleValueChange,
}: PublishBarProps) {
  const hasSchedule = arms.some((a) => a.mode === "schedule");
  const handlers: Record<PublishCtaArm["mode"], () => void> = {
    draft: onSaveDraft,
    publish: onPublish,
    schedule: onSchedule,
  };

  return (
    <div className="flex flex-wrap items-center justify-end gap-2">
      {hasSchedule && (
        <Input
          type="datetime-local"
          aria-label="Schedule publish time"
          value={scheduleValue}
          onChange={(e) => onScheduleValueChange(e.target.value)}
          className="h-8 w-auto"
        />
      )}
      {arms.map((arm) => (
        <Button
          key={arm.mode}
          type="button"
          variant={arm.variant}
          disabled={arm.disabled}
          onClick={handlers[arm.mode]}
        >
          {arm.busy && <Loader2 className={cn("size-4 animate-spin")} />}
          {arm.label}
        </Button>
      ))}
    </div>
  );
}

"use client";

import type { Ref } from "react";
import type {
  ComposerStep,
  ComposerStepCtx,
  SlotHandle,
  SlotKind,
  SlotSubstrateMap,
  SlotValueFor,
} from "../types";
import { findSubstrate } from "../lib/substrates";
import {
  MissingSubstrateFallback,
  warnMissingSubstrate,
} from "./missing-substrate";

export interface SlotMountProps {
  /** the merged substrate map (DEFAULT_SUBSTRATES under consumer overrides) */
  substrates: SlotSubstrateMap;
  step: ComposerStep;
  value: SlotValueFor<SlotKind> | undefined;
  onChange: (next: SlotValueFor<SlotKind>) => void;
  ctx: ComposerStepCtx;
  /** the shell threads a ref the substrate populates with a uniform SlotHandle */
  handleRef: Ref<SlotHandle<SlotValueFor<SlotKind>>>;
}

/**
 * Looks up the substrate for a step's slot-kind and renders it — or a degraded
 * fallback if none is registered. The fallback is a RENDER concern (NON-blocking):
 * navigation still works and the validation gate passes on a missing substrate
 * (see the gate's `if (!handle) return { ok: true }`). DISTINCT from the blocking
 * validation gate (mirrors kanban's `item-renderer.tsx`).
 */
export function SlotMount({
  substrates,
  step,
  value,
  onChange,
  ctx,
  handleRef,
}: SlotMountProps) {
  const substrate = findSubstrate(substrates, step.slot);
  if (!substrate) {
    warnMissingSubstrate(step.slot);
    return <MissingSubstrateFallback slotKind={step.slot} />;
  }
  return (
    <>
      {substrate.render({
        slotConfig: step.slotConfig,
        value,
        onChange,
        ctx,
        handleRef,
      })}
    </>
  );
}

"use client";

import { Check, TriangleAlert } from "lucide-react";
import { cn } from "@/lib/utils";
import type { ComposerStep } from "../types";

export interface StepIndicatorProps {
  steps: ComposerStep[];
  /** index into `steps` of the active step */
  cursor: number;
  /** per-step error slices (keyed by step id) */
  stepErrors: Record<string, string[]>;
  /** invoked with the target step index; the shell runs the gate (forward) or jumps free (backward) */
  onStepClick: (index: number) => void;
}

/**
 * Labeled step nav (`<nav aria-label="Composer steps">`) with `aria-current="step"`
 * on the active step. Past steps render a check; errored steps render a warning.
 * Backward steps are always reachable; forward jumps run the blocking gate (the
 * shell decides — this is a presentational click surface).
 */
export function StepIndicator({
  steps,
  cursor,
  stepErrors,
  onStepClick,
}: StepIndicatorProps) {
  return (
    <nav aria-label="Composer steps">
      <ol className="flex flex-wrap items-center gap-1.5">
        {steps.map((step, i) => {
          const isCurrent = i === cursor;
          const isComplete = i < cursor;
          const hasError = (stepErrors[step.id]?.length ?? 0) > 0;
          return (
            <li key={step.id} className="flex items-center gap-1.5">
              <button
                type="button"
                aria-current={isCurrent ? "step" : undefined}
                onClick={() => onStepClick(i)}
                className={cn(
                  "group flex items-center gap-2 rounded-full py-1 pr-3 pl-1 text-sm transition-colors",
                  "focus-visible:ring-2 focus-visible:ring-ring focus-visible:outline-none",
                  isCurrent
                    ? "bg-primary/15 text-foreground"
                    : "text-muted-foreground hover:bg-muted hover:text-foreground",
                )}
              >
                <span
                  className={cn(
                    "flex size-6 shrink-0 items-center justify-center rounded-full text-xs font-medium tabular-nums",
                    hasError
                      ? "bg-destructive/15 text-destructive"
                      : isCurrent
                        ? "bg-primary text-primary-foreground"
                        : isComplete
                          ? "bg-primary/25 text-foreground"
                          : "bg-muted text-muted-foreground",
                  )}
                >
                  {hasError ? (
                    <TriangleAlert className="size-3.5" />
                  ) : isComplete ? (
                    <Check className="size-3.5" />
                  ) : (
                    i + 1
                  )}
                </span>
                <span className={cn("font-medium", isCurrent && "text-foreground")}>
                  {step.title}
                </span>
              </button>
              {i < steps.length - 1 && (
                <span
                  aria-hidden
                  className="h-px w-4 shrink-0 bg-border sm:w-6"
                />
              )}
            </li>
          );
        })}
      </ol>
    </nav>
  );
}
